Fix an interface design issue: `IFileService.UploadAsync` returns `Task` (void), forcing the controller to reconstruct the stored path client-side, duplicating normalization logic.

**The change:**

1. **`Services/IFileService.cs`** — Change the return type of `UploadAsync` from `Task` to `Task<string>`. Update the XML doc comment to say it returns the stored file's normalized relative path.

2. **`Services/FileService.cs`** — Change `UploadAsync` to return `Task<string>`. After writing the file, return `ToRelative(path)` — the service's own `ToRelative` helper already normalizes the stored path to a forward-slash relative path. This eliminates the need for the controller to reconstruct the path. The `ToRelative(path)` call uses the absolute path that was just written (`Path.Combine(dir, fileName)`), so it correctly reflects the actual stored location including the sanitized file name.

3. **`Controllers/FilesController.cs`** — Simplify the `Upload` endpoint body. Instead of calling `_service.UploadAsync(...)` then reconstructing the path with `NormalizeRelativePath`, capture the returned path directly:
   ```csharp
   var storedPath = await _service.UploadAsync(path ?? string.Empty, file);
   return Ok(new { path = storedPath });
   ```
   Remove the now-unused `NormalizeRelativePath` private static helper method entirely (it was only used by Upload). Also remove its XML doc comment.

4. **`TestProject.Tests/Controllers/FakeFileService.cs`** — Update `UploadAsync` to return `Task<string>`. Add a configurable output field `public string UploadedPath = string.Empty;` and return it from `UploadAsync` (after recording inputs and checking for faults, same pattern as the other methods). Update the existing return to `return Task.FromResult(UploadedPath);` or `return UploadedPath;` (since the method is non-async, use `Task.FromResult`).

5. **`TestProject.Tests/Controllers/FilesControllerTests.cs`** — Update any Upload tests that assert on the response path. The tests that check the returned `path` property should now verify the service's returned value is passed through unchanged. If any test asserts the controller reconstructs the path via normalization, update it to assert the service's returned value is echoed directly.

This is a behavior-preserving change from the API consumer's perspective: the upload response still contains `{ path: "..." }` with the stored file's relative path. The only difference is the path is now sourced from the service (which is the source of truth) rather than reconstructed by the controller.

Verification: Run `dotnet build TestProject.sln` and `dotnet test TestProject.sln`. Confirm all tests pass, especially the Upload controller tests.

## Review Feedback History (please address all items)
Attempt 1: The test changes are well-designed overall. The FileServiceTests.cs return-value tests are thorough (normalization, traversal stripping, forward-slash invariance, round-trip invariant). The controller tests correctly verify verbatim echo behavior, raw path forwarding, and error handling. However, the build fails because IFileService.UploadAsync still returns Task while the test doubles return Task<string> — the production code must be updated for the tests to compile. Additionally, three standalone echo tests are near-duplicates of the parameterized Upload_ResponsePath_EchoesServiceReturnValue_VerbatimWithoutNormalization test and could be removed.

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary.
    /// </summary>
    Task UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);

    /// <summary>
    /// Creates the directory at <paramref name="relativePath"/> (including any
    /// missing parent directories), confined to the home root. Idempotent: a
    /// path that already exists as a directory is a no-op.
    /// </summary>
    void CreateDirectory(string relativePath);
}

using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Path-safe implementation of <see cref="IFileService"/> that confines every
/// operation to a single home directory. The root path is computed at
/// construction time, but the directory itself is created lazily on first use
/// so that disk I/O (and any failure it might raise) is decoupled from DI
/// resolution. Any relative path that normalizes to a location outside the
/// home root causes an <see cref="ArgumentException"/> to be thrown before any
/// disk access.
/// </summary>
public sealed class FileService : IFileService
{
    private const int MaxSearchResults = 500;

    /// <summary>
    /// Maximum recursion depth permitted for <see cref="CopyDirectory"/>. A
    /// copy that recurses this many levels deep is treated as a pathological or
    /// self-referential tree and aborted with <see cref="IOException"/> to
    /// guard against stack overflow.
    /// </summary>
    private const int MaxCopyDepth = 32;

    /// <summary>
    /// Characters disallowed in a stored file name on any supported platform.
    /// This is the union of <see cref="Path.GetInvalidFileNameChars"/> (which
    /// is platform-specific — on Linux it returns only NUL and '/') with the
    /// Windows-only separators and metacharacters, so a name accepted on Linux
    /// is guaranteed to be acceptable on Windows too. Without this, an upload
    /// like <c>report:2024.txt</c> succeeds on Linux but throws on Windows.
    /// </summary>
    private static readonly char[] s_invalidFileNameChars = Path.GetInvalidFileNameChars()
        .Concat(new[] { '\\', '/', ':', '*', '?', '"', '<', '>', '|' })
        .Distinct()
        .ToArray();

    /// <summary>
    /// File-name stems that Windows reserves regardless of extension (e.g.
    /// <c>CON.txt</c> is reserved just like <c>CON</c>). Rejected on every
    /// platform so an upload accepted on Linux cannot fail on Windows.
    /// </summary>
    private static readonly HashSet<string> s_reservedWindowsDeviceNames = new(StringComparer.OrdinalIgnoreCase)
    {
        "CON", "PRN", "AUX", "NUL",
        "COM1", "COM2", "COM3", "COM4", "COM5", "COM6", "COM7", "COM8", "COM9",
        "LPT1", "LPT2", "LPT3", "LPT4", "LPT5", "LPT6", "LPT7", "LPT8", "LPT9",
    };

    private readonly Lazy<string> _rootLazy;

    public FileService(IOptions<FileServiceOptions> options, IWebHostEnvironment env)
    {
        // Only compute the resolved path here. Creating the directory (and
        // surfacing any I/O failure) is deferred to first use via the Lazy,
        // which is thread-safe so the directory is materialized exactly once
        // even under concurrent first-access.
        _rootLazy = new Lazy<string>(
            () =>
            {
                var root = Path.GetFullPath(Path.Combine(
                    env.ContentRootPath,
                    options.Value.HomeDirectory ?? "Home"));
                Directory.CreateDirectory(root);
                return root;
            },
            LazyThreadSafetyMode.ExecutionAndPublication);
    }

    /// <summary>
    /// The resolved home root, materializing it on first access.
    /// </summary>
    private string Root => _rootLazy.Value;

    // =====================================================================
    // IFileService
    // =====================================================================

    /// <inheritdoc />
    public BrowseResultDto Browse(string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        // Enumerate files and directories in a single pass, avoiding the
        // double traversal (and double array allocation) of separate
        // GetDirectories/GetFiles calls. Name, FullName, and LastWriteTimeUtc
        // are exposed by the shared FileSystemInfo base; only the file size
        // requires the FileInfo cast.
        var entries = new List<FileEntryDto>();

        foreach (var info in new DirectoryInfo(full).EnumerateFileSystemInfos())
        {
            if (info is DirectoryInfo directoryInfo)
            {
                entries.Add(new FileEntryDto(
                    Name: directoryInfo.Name,
                    Path: ToRelative(directoryInfo.FullName),
                    IsDirectory: true,
                    Size: 0,
                    LastModified: directoryInfo.LastWriteTimeUtc,
                    ItemCount: CountImmediateItems(directoryInfo)));
            }
            else
            {
                var fileInfo = (FileInfo)info;
                entries.Add(new FileEntryDto(
                    Name: fileInfo.Name,
                    Path: ToRelative(fileInfo.FullName),
                    IsDirectory: false,
                    Size: fileInfo.Length,
                    LastModified: fileInfo.LastWriteTimeUtc,
                    ItemCount: 0));
            }
        }

        // Directories first, then files, each group sorted by name (OrdinalIgnoreCase).
        entries.Sort(CompareEntries);

        var folderCount = 0;
        var fileCount = 0;
        var totalSize = 0L;
        foreach (var entry in entries)
        {
            if (entry.IsDirectory)
            {
                folderCount++;
            }
            else
            {
                fileCount++;
                totalSize += entry.Size;
            }
        }

        var parent = ComputeParent(relative);

        return new BrowseResultDto(relative, parent, entries, folderCount, fileCount, totalSize);
    }

    /// <inheritdoc />
    public SearchResultDto Search(string query, string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var results = new List<FileEntryDto>(MaxSearchResults);

        var stack = new Stack<string>();
        stack.Push(full);

        while (stack.Count > 0 && results.Count < MaxSearchResults)
        {
            var current = stack.Pop();

            string[] subdirectories;
            string[] files;
            try
            {
                subdirectories = Directory.GetDirectories(current);
                files = Directory.GetFiles(current);
            }
            catch (UnauthorizedAccessException)
            {
                continue;
            }
            catch (DirectoryNotFoundException)
            {
                continue;
            }

            foreach (var dir in subdirectories)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new DirectoryInfo(dir);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(dir),
                        IsDirectory: true,
                        Size: 0,
                        LastModified: info.LastWriteTimeUtc,
                        ItemCount: CountImmediateItems(info)));
                }

                // Do not descend into reparse points (symbolic links on
                // Linux/macOS, directory junctions/symlinks on Windows): they
                // may target a location outside the home sandbox, and following
                // them would let Search enumerate content beyond the root. The
                // link is still eligible to appear as a match above.
                if (!IsReparsePoint(info))
                {
                    stack.Push(dir);
                }
            }

            foreach (var file in files)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new FileInfo(file);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(file),
                        IsDirectory: false,
                        Size: info.Length,
                        LastModified: info.LastWriteTimeUtc,
                        ItemCount: 0));
                }
            }
        }

        return new SearchResultDto(query, relative, results);
    }

    /// <inheritdoc />
    public string ResolveFullPath(string relativePath) => SafeResolve(relativePath);

    /// <inheritdoc />
    public async Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        var dir = SafeResolve(relativeDirPath);
        Directory.CreateDirectory(dir);

        // The uploaded file name is untrusted client input. Reduce it to its
        // final, safe segment and validate it (see PrepareUploadedFileName)
        // before it is combined with the sandboxed directory. This blocks path
        // traversal ("../x", "..\x") on both platforms and rejects names that
        // are illegal on Windows, so an upload accepted on Linux cannot fail
        // when the app is deployed to Windows.
        var fileName = PrepareUploadedFileName(file.FileName);
        var path = Path.Combine(dir, fileName);

        await using var fs = File.Create(path);
        await file.CopyToAsync(fs);
    }

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// Deleting a non-existent path succeeds silently — the post-condition
    /// (entry gone) is already met.
    /// </summary>
    /// <remarks>
    /// Dispatch is driven by existence checks rather than by the exception
    /// type thrown by <see cref="Directory.Delete(string, bool)"/>, because
    /// that type is platform-dependent: on Linux deleting a path that is a
    /// file (or missing) throws <see cref="DirectoryNotFoundException"/>, but
    /// on Windows deleting an existing file throws <see cref="IOException"/>
    /// ("A file with the same name and location specified by path exists").
    /// A narrow race remains — a directory removed between
    /// <see cref="Directory.Exists(string)"/> and the delete call — but it is
    /// swallowed, so the worst case is a benign no-op rather than a spurious
    /// error.
    /// </remarks>
    public void Delete(string relativePath)
    {
        var path = SafeResolve(relativePath);

        if (Directory.Exists(path))
        {
            try
            {
                Directory.Delete(path, recursive: true);
            }
            catch (DirectoryNotFoundException)
            {
                // Vanished between the existence check and the delete (a
                // concurrent removal). The post-condition — the entry is
                // gone — already holds, so swallow the race.
            }
            return;
        }

        if (File.Exists(path))
        {
            // File.Delete is a documented no-op when the target is
            // concurrently removed, so no equivalent race guard is needed.
            File.Delete(path);
        }
        // else: neither a directory nor a file — already absent (including
        // the case where the parent directory never existed), which satisfies
        // the idempotent "entry gone" post-condition without touching disk.
    }

    /// <inheritdoc />
    public void Move(MoveRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        // Path.GetDirectoryName returns null when the destination is a
        // filesystem root (e.g. the home root itself). Moving an entry onto a
        // filesystem root is nonsensical within the home-directory sandbox, so
        // surface a clear error rather than letting
        // Directory.CreateDirectory(null) crash with an opaque
        // ArgumentNullException.
        var parent = Path.GetDirectoryName(destination);
        if (string.IsNullOrEmpty(parent))
        {
            throw new ArgumentException("Invalid destination path", nameof(request));
        }

        Directory.CreateDirectory(parent);

        if (Directory.Exists(source))
        {
            Directory.Move(source, destination);
        }
        else
        {
            File.Move(source, destination);
        }
    }

    /// <inheritdoc />
    public void Copy(CopyRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        if (Directory.Exists(source))
        {
            CopyDirectory(source, destination, depth: 0);
        }
        else
        {
            File.Copy(source, destination, overwrite: false);
        }
    }

    /// <inheritdoc />
    /// <remarks>
    /// <see cref="Directory.CreateDirectory(string)"/> is idempotent (a no-op
    /// when the directory already exists) and creates every missing parent, so
    /// a multi-segment relative path materializes the whole chain. The path is
    /// sandboxed by <see cref="SafeResolve"/> before any disk access, so a path
    /// that escapes the home root throws <see cref="ArgumentException"/>
    /// unchanged (translated to 400 by the controller). Creating over an
    /// existing <em>file</em> path would throw <see cref="IOException"/>, which
    /// the controller likewise translates to 400.
    /// </remarks>
    public void CreateDirectory(string relativePath)
    {
        Directory.CreateDirectory(SafeResolve(relativePath));
    }

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Combines the home root with <paramref name="relativePath"/>, normalizes
    /// the result, and verifies it stays within the root. A null, empty, or
    /// whitespace path resolves to the root itself. Anything that escapes the
    /// root throws <see cref="ArgumentException"/>.
    /// </summary>
    private string SafeResolve(string relativePath)
    {
        var root = Root;

        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return root;
        }

        var full = Path.GetFullPath(Path.Combine(root, relativePath));

        var isRoot = string.Equals(full, root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Converts an absolute path inside the root to a forward-slash relative
    /// path. The root itself becomes the empty string.
    /// </summary>
    private string ToRelative(string full)
    {
        var root = Root;
        return full
            .Substring(root.Length)
            .TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
            .Replace('\\', '/');
    }

    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    private static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        return Path.GetDirectoryName(relative)?.Replace('\\', '/') ?? string.Empty;
    }

    /// <summary>
    /// Sorts directories before files, ordering each group by name using
    /// <see cref="StringComparison.OrdinalIgnoreCase"/>.
    /// </summary>
    private static int CompareEntries(FileEntryDto a, FileEntryDto b)
    {
        if (a.IsDirectory != b.IsDirectory)
        {
            return a.IsDirectory ? -1 : 1;
        }

        return string.Compare(a.Name, b.Name, StringComparison.OrdinalIgnoreCase);
    }

    /// <summary>
    /// Counts the immediate children (files + subdirectories) of a directory,
    /// used to populate a directory entry's <see cref="FileEntryDto.ItemCount"/>
    /// for display in the Size column. Only direct children are counted —
    /// nested contents below a subdirectory are NOT included. Returns 0 for an
    /// empty or inaccessible directory, and for a reparse point (symbolic link
    /// / junction): following such a link would enumerate content outside the
    /// home sandbox, so it is reported as having no visible children rather
    /// than descending into its (possibly external) target. Enumeration errors
    /// (access denied, directory removed between the listing and the count)
    /// are swallowed and reported as 0 so one unreadable folder cannot abort a
    /// browse/search response.
    /// </summary>
    private static int CountImmediateItems(DirectoryInfo directoryInfo)
    {
        if (IsReparsePoint(directoryInfo))
        {
            return 0;
        }

        try
        {
            var count = 0;
            foreach (var _ in directoryInfo.EnumerateFileSystemInfos())
            {
                count++;
            }
            return count;
        }
        catch (UnauthorizedAccessException)
        {
            return 0;
        }
        catch (DirectoryNotFoundException)
        {
            return 0;
        }
    }

    /// <summary>
    /// Reduces an untrusted uploaded file name to its final, safe segment and
    /// validates it. Leading directory components are stripped by treating
    /// both '/' and '\' as separators (a backslash is a separator on Windows
    /// but a literal character on Linux, so handling both closes the
    /// cross-platform traversal gap), and the resulting name is rejected when
    /// it is empty, contains a character invalid on Windows, or matches a
    /// reserved Windows device name. The returned name contains no separators
    /// and is therefore safe to combine with an already-sandboxed directory.
    /// </summary>
    private static string PrepareUploadedFileName(string? rawFileName)
    {
        var segment = (rawFileName ?? string.Empty)
            .Replace('\\', '/')
            .Split('/')
            .LastOrDefault(s => s.Length > 0 && s != "." && s != "..")
            ?? string.Empty;

        // Trim surrounding whitespace. Windows strips leading/trailing spaces
        // (and dots) from file names at the filesystem layer, so a name that is
        // only whitespace cannot exist there; trimming everywhere keeps Linux
        // consistent and reduces a whitespace-only name to the empty string,
        // which is rejected below.
        segment = segment.Trim();

        if (segment.Length == 0)
        {
            throw new ArgumentException("Invalid file name");
        }

        if (segment.IndexOfAny(s_invalidFileNameChars) >= 0)
        {
            throw new ArgumentException("File name contains invalid characters");
        }

        // Windows reserves device names like "CON" even with an extension
        // ("CON.txt"), so test the stem before the first dot.
        var dot = segment.IndexOf('.');
        var stem = dot < 0 ? segment : segment[..dot];
        if (s_reservedWindowsDeviceNames.Contains(stem))
        {
            throw new ArgumentException("File name is reserved");
        }

        return segment;
    }

    /// <summary>
    /// Determines whether the given file-system entry is a reparse point (a
    /// symbolic link on Linux/macOS, a symbolic link or directory junction on
    /// Windows). The attributes of the entry itself are inspected — not those
    /// of its target — so the link is never followed.
    /// </summary>
    private static bool IsReparsePoint(FileSystemInfo info)
        => (info.Attributes & FileAttributes.ReparsePoint) != 0;

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten, matching the no-overwrite contract of
    /// <see cref="File.Copy(string, string, bool)"/>. The recursion is bounded
    /// by <see cref="MaxCopyDepth"/>: each nested directory increments
    /// <paramref name="depth"/> by one, and once it reaches the limit the copy
    /// is aborted with <see cref="IOException"/> to prevent stack overflow on
    /// pathological or self-referential trees.
    /// </summary>
    /// <param name="source">Absolute path to the directory to copy from.</param>
    /// <param name="destination">Absolute path to the directory to copy into.</param>
    /// <param name="depth">Current recursion depth, seeded at zero by
    /// <see cref="Copy"/>.</param>
    private static void CopyDirectory(string source, string destination, int depth)
    {
        if (depth >= MaxCopyDepth)
        {
            throw new IOException("Directory copy depth limit exceeded (possible cycle)");
        }

        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            // Skip reparse points (e.g. symlinked files): File.Copy follows
            // the link and would copy the target's contents, which may live
            // outside the home sandbox. Such entries are not reproduced.
            if (IsReparsePoint(new FileInfo(file)))
            {
                continue;
            }

            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            // Skip reparse points (symbolic links / junctions to
            // directories): recursing into them would follow the link and copy
            // content from outside the home sandbox. The link entry itself is
            // not reproduced in the destination.
            if (IsReparsePoint(new DirectoryInfo(directory)))
            {
                continue;
            }

            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)), depth + 1);
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Controllers;

/// <summary>
/// HTTP API surface for the path-safe file system operations exposed by
/// <see cref="IFileService"/>. Every endpoint is rooted under
/// <c>/api/files</c> and delegates its work to <see cref="Execute"/> (or
/// <see cref="ExecuteAsync"/> for the async <see cref="Upload"/> endpoint),
/// which translates the well-known file system faults
/// (<see cref="ArgumentException"/>, <see cref="UnauthorizedAccessException"/>,
/// <see cref="DirectoryNotFoundException"/>, <see cref="FileNotFoundException"/>
/// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying the
/// exception message, leaving any other exception type to propagate.
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class FilesController : ControllerBase
{
    private readonly IFileService _service;
    private static readonly FileExtensionContentTypeProvider ContentTypeProvider = new();

    /// <summary>Fallback MIME type used when the file extension cannot be resolved.</summary>
    private const string DefaultContentType = "application/octet-stream";

    /// <summary>
    /// Creates a new <see cref="FilesController"/> bound to the supplied
    /// <paramref name="service"/>.
    /// </summary>
    public FilesController(IFileService service)
    {
        _service = service;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="path"/>
    /// (the root when omitted or empty), returning directories first then
    /// files, each group sorted by name.
    /// </summary>
    [HttpGet("browse")]
    public ActionResult<BrowseResultDto> Browse([FromQuery] string? path)
        => Execute(() => Ok(_service.Browse(path ?? string.Empty)));

    // =====================================================================
    // Search
    // =====================================================================

    /// <summary>
    /// Recursively searches under <paramref name="path"/> (the root when
    /// omitted or empty) for entries whose name contains <paramref name="query"/>
    /// (case-insensitive).
    /// </summary>
    [HttpGet("search")]
    public ActionResult<SearchResultDto> Search([FromQuery] string query, [FromQuery] string? path)
        => Execute(() => Ok(_service.Search(query ?? string.Empty, path ?? string.Empty)));

    // =====================================================================
    // Upload
    // =====================================================================

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="path"/> (the root when omitted or empty), creating it
    /// if necessary. The response reports the joined relative path of the
    /// stored file.
    /// </summary>
    [HttpPost("upload")]
    public async Task<IActionResult> Upload([FromQuery] string? path, [FromForm] IFormFile file)
        => await ExecuteAsync(async () =>
        {
            await _service.UploadAsync(path ?? string.Empty, file);
            var dir = NormalizeRelativePath(path ?? string.Empty);
            // The file name is normalized too: the service stores only the
            // safe final segment (see FileService.UploadAsync), so the
            // response must reflect that same segment rather than echo back
            // the raw — possibly path-like or traversal-laden — input.
            var fileName = NormalizeRelativePath(file.FileName);
            var resultPath = string.Join('/',
                new[] { dir, fileName }.Where(s => s.Length > 0));
            return Ok(new { path = resultPath });
        });

    // =====================================================================
    // Download
    // =====================================================================

    /// <summary>
    /// Streams the file at <paramref name="path"/> as a physical file
    /// response, deriving the content type from the extension (defaulting to
    /// <see cref="DefaultContentType"/> when unknown).
    /// </summary>
    [HttpGet("download")]
    public IActionResult Download([FromQuery] string path)
        => Execute(() =>
        {
            var full = _service.ResolveFullPath(path);
            var contentType = ContentTypeProvider.TryGetContentType(full, out var ct)
                ? ct
                : DefaultContentType;
            return PhysicalFile(full, contentType, Path.GetFileName(full));
        });

    // =====================================================================
    // Delete
    // =====================================================================

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="path"/>.
    /// </summary>
    [HttpDelete("delete")]
    public IActionResult Delete([FromQuery] string path)
        => Execute(() =>
        {
            _service.Delete(path);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Move
    // =====================================================================

    /// <summary>
    /// Moves the file or directory at <paramref name="request"/>'s
    /// <see cref="MoveRequest.SourcePath"/> to its
    /// <see cref="MoveRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("move")]
    public IActionResult Move([FromBody] MoveRequest request)
        => Execute(() =>
        {
            _service.Move(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Copy
    // =====================================================================

    /// <summary>
    /// Copies the file or directory at <paramref name="request"/>'s
    /// <see cref="CopyRequest.SourcePath"/> to its
    /// <see cref="CopyRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("copy")]
    public IActionResult Copy([FromBody] CopyRequest request)
        => Execute(() =>
        {
            _service.Copy(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Create directory
    // =====================================================================

    /// <summary>
    /// Creates the directory at <paramref name="path"/> (including any missing
    /// parents), creating the home root itself when omitted or empty. The
    /// operation is idempotent: an existing directory is left as-is.
    /// </summary>
    [HttpPost("mkdir")]
    public IActionResult CreateDirectory([FromQuery] string? path)
        => Execute(() =>
        {
            _service.CreateDirectory(path ?? string.Empty);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Runs <paramref name="body"/> and translates the well-known file system
    /// faults (<see cref="ArgumentException"/>,
    /// <see cref="UnauthorizedAccessException"/>,
    /// <see cref="DirectoryNotFoundException"/>, <see cref="FileNotFoundException"/>
    /// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying
    /// the exception message. Any other exception type propagates unchanged.
    /// </summary>
    /// <remarks>
    /// The return type is <see cref="ActionResult"/> (rather than
    /// <see cref="IActionResult"/>) so the same helper can back both the
    /// <see cref="Browse"/>/<see cref="Search"/> endpoints, whose return type
    /// is <c>ActionResult&lt;T&gt;</c>, and the plain
    /// <see cref="IActionResult"/> endpoints; <see cref="ActionResult"/>
    /// implements <see cref="IActionResult"/> and converts implicitly to
    /// <c>ActionResult&lt;T&gt;</c>, while <see cref="IActionResult"/> does not.
    /// </remarks>
    private ActionResult Execute(Func<ActionResult> body)
    {
        try
        {
            return body();
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// Async variant of <see cref="Execute"/> for endpoints that must await
    /// service calls (currently <see cref="Upload"/>). Same catch list and
    /// translation; non-translated exceptions propagate. The body is awaited
    /// (never unwrapped via <c>.Result</c>/<c>.Wait()</c>) so a faulting body
    /// surfaces its original exception rather than an
    /// <see cref="AggregateException"/>.
    /// </summary>
    private async Task<ActionResult> ExecuteAsync(Func<Task<ActionResult>> body)
    {
        try
        {
            return await body();
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// Normalizes a raw directory path for use in the response: replaces
    /// backslashes with forward slashes, collapses repeated slashes, and
    /// removes <c>.</c> and <c>..</c> segments. Returns empty string when
    /// the path is null, empty, or collapses to nothing.
    /// </summary>
    private static string NormalizeRelativePath(string raw)
    {
        if (string.IsNullOrEmpty(raw))
            return string.Empty;

        return string.Join("/",
            raw.Replace('\\', '/')
               .Split('/')
               .Where(s => s.Length > 0 && s != "." && s != ".."));
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Recording double for <see cref="IFileService"/>. Each method stashes the
/// arguments it was called with and either returns a configurable value or
/// throws a configurable exception, giving each test full control over the
/// service's behavior while keeping the double trivially inspectable.
/// </summary>
public sealed class FakeFileService : IFileService
{
    // ----- recorded inputs -----
    public string? BrowsePath;
    public string? SearchQuery;
    public string? SearchPath;
    public string? ResolvePath;
    public string? UploadDirPath;
    public IFormFile? UploadFile;
    public string? DeletePath;
    public MoveRequest? MoveRequest;
    public CopyRequest? CopyRequest;
    public string? CreateDirectoryPath;

    // ----- configurable outputs / faults -----
    public BrowseResultDto BrowseResult = new(string.Empty, null, Array.Empty<FileEntryDto>(), 0, 0, 0L);
    public SearchResultDto SearchResult = new(string.Empty, string.Empty, Array.Empty<FileEntryDto>());
    public string ResolvedPath = string.Empty;
    /// <summary>
    /// The stored relative path <see cref="UploadAsync"/> reports back to the
    /// caller. Mirrors the real <c>FileService.UploadAsync</c> return value so
    /// controller tests can assert the returned path is echoed verbatim.
    /// </summary>
    public string UploadedPath = string.Empty;
    public Exception? BrowseException;
    public Exception? SearchException;
    public Exception? ResolveException;
    public Exception? UploadException;
    public Exception? DeleteException;
    public Exception? MoveException;
    public Exception? CopyException;
    public Exception? CreateDirectoryException;

    public BrowseResultDto Browse(string relativePath)
    {
        BrowsePath = relativePath;
        if (BrowseException is not null) throw BrowseException;
        return BrowseResult;
    }

    public SearchResultDto Search(string query, string relativePath)
    {
        SearchQuery = query;
        SearchPath = relativePath;
        if (SearchException is not null) throw SearchException;
        return SearchResult;
    }

    public string ResolveFullPath(string relativePath)
    {
        ResolvePath = relativePath;
        if (ResolveException is not null) throw ResolveException;
        return ResolvedPath;
    }

    public Task<string> UploadAsync(string relativeDirPath, IFormFile file)
    {
        UploadDirPath = relativeDirPath;
        UploadFile = file;
        if (UploadException is not null) throw UploadException;
        return Task.FromResult(UploadedPath);
    }

    public void Delete(string relativePath)
    {
        DeletePath = relativePath;
        if (DeleteException is not null) throw DeleteException;
    }

    public void Move(MoveRequest request)
    {
        MoveRequest = request;
        if (MoveException is not null) throw MoveException;
    }

    public void Copy(CopyRequest request)
    {
        CopyRequest = request;
        if (CopyException is not null) throw CopyException;
    }

    public void CreateDirectory(string relativePath)
    {
        CreateDirectoryPath = relativePath;
        if (CreateDirectoryException is not null) throw CreateDirectoryException;
    }
}

using System.Reflection;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Infrastructure;
using TestProject.Controllers;
using TestProject.Models;
using TestProject.Services;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Behavioral tests for <see cref="FilesController"/>. Each test drives the
/// controller with a configurable <see cref="FakeFileService"/> and asserts
/// on the returned <see cref="IActionResult"/>: the happy paths verify that
/// the service is invoked with the normalized inputs and that the response
/// payload has the documented shape, while the error paths verify that the
/// five catch-and-translate exception types yield a 400 with the message.
///
/// The controller is exercised directly (not through the ASP.NET Core
/// pipeline) so model-binding attributes like <c>[FromQuery]</c> are not
/// applied; arguments are passed as ordinary method parameters.
/// </summary>
public class FilesControllerTests
{
    /// <summary>
    /// The five exception types the controller must catch and translate into
    /// a <c>BadRequest</c>. Note <see cref="DirectoryNotFoundException"/> and
    /// <see cref="FileNotFoundException"/> are <see cref="IOException"/>
    /// subtypes, but are enumerated explicitly to match the documented
    /// catch list.
    /// </summary>
    public static IEnumerable<object[]> CaughtExceptions()
    {
        // The five exception types the controller documents and catches by
        // name. Each must map to a 400 carrying its Message.
        yield return new object[] { new ArgumentException("arg-message") };
        yield return new object[] { new UnauthorizedAccessException("unauth-message") };
        yield return new object[] { new DirectoryNotFoundException("dir-message") };
        yield return new object[] { new FileNotFoundException("file-message") };
        yield return new object[] { new IOException("io-message") };

        // Subtypes that must be caught by virtue of inheritance. The catch
        // list names base types (ArgumentException, IOException), so derived
        // exceptions must ALSO resolve to 400; exact-type matching would let
        // these leak through as unhandled. These cases pin the
        // inheritance-based contract of the shared helper.
        yield return new object[] { new ArgumentNullException("p", "argnull-message") };
        yield return new object[] { new ArgumentOutOfRangeException("p", "argoor-message") };
        yield return new object[] { new PathTooLongException("pathtoolong-message") };
    }

    private static FilesController CreateController(FakeFileService service)
    {
        return new FilesController(service);
    }

    private static object? GetProperty(object instance, string name)
    {
        var property = instance.GetType().GetProperty(name);
        Assert.NotNull(property);
        return property!.GetValue(instance);
    }

    /// <summary>
    /// Asserts that <paramref name="value"/> exposes exactly one public
    /// property, named <paramref name="expectedName"/>, and returns it for
    /// further type/value assertions. Used to pin the *exact* payload shape
    /// of the Ok/BadRequest anonymous bodies against added, renamed, dropped,
    /// or retyped fields.
    /// </summary>
    private static PropertyInfo AssertSingleProperty(object value, string expectedName)
    {
        var property = Assert.Single(value.GetType().GetProperties());
        Assert.Equal(expectedName, property.Name);
        return property;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    [Fact]
    public void Browse_ReturnsOk200_WithServiceResult()
    {
        var dto = new BrowseResultDto("docs", "", Array.Empty<FileEntryDto>(), 0, 0, 0L);
        var fake = new FakeFileService { BrowseResult = dto };
        var controller = CreateController(fake);

        var actionResult = controller.Browse("docs");

        var ok = Assert.IsType<OkObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Same(dto, ok.Value);
    }

    [Fact]
    public void Browse_PassesProvidedPathToService()
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Browse("docs/sub");

        Assert.Equal("docs/sub", fake.BrowsePath);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void Browse_PassesEmptyString_WhenPathIsNullOrEmpty(string? path)
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Browse(path);

        Assert.Equal(string.Empty, fake.BrowsePath);
    }

    [Theory]
    [MemberData(nameof(CaughtExceptions))]
    public void Browse_WhenServiceThrows_ReturnsBadRequest400_WithErrorMessage(Exception ex)
    {
        var fake = new FakeFileService { BrowseException = ex };
        var controller = CreateController(fake);

        var actionResult = controller.Browse("any");

        var badRequest = Assert.IsType<BadRequestObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status400BadRequest, badRequest.StatusCode);
        Assert.Equal(ex.Message, GetProperty(badRequest.Value!, "error"));
    }

    // =====================================================================
    // Search
    // =====================================================================

    [Fact]
    public void Search_ReturnsOk200_WithServiceResult()
    {
        var dto = new SearchResultDto("report", "docs", Array.Empty<FileEntryDto>());
        var fake = new FakeFileService { SearchResult = dto };
        var controller = CreateController(fake);

        var actionResult = controller.Search("report", "docs");

        var ok = Assert.IsType<OkObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Same(dto, ok.Value);
    }

    [Fact]
    public void Search_PassesQueryAndPathToService()
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Search("report", "docs");

        Assert.Equal("report", fake.SearchQuery);
        Assert.Equal("docs", fake.SearchPath);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void Search_PassesEmptyQuery_WhenQueryIsNullOrEmpty(string? query)
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Search(query!, "docs");

        Assert.Equal(string.Empty, fake.SearchQuery);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void Search_PassesEmptyPath_WhenPathIsNullOrEmpty(string? path)
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Search("report", path);

        Assert.Equal(string.Empty, fake.SearchPath);
    }

    [Theory]
    [MemberData(nameof(CaughtExceptions))]
    public void Search_WhenServiceThrows_ReturnsBadRequest400_WithErrorMessage(Exception ex)
    {
        var fake = new FakeFileService { SearchException = ex };
        var controller = CreateController(fake);

        var actionResult = controller.Search("q", "p");

        var badRequest = Assert.IsType<BadRequestObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status400BadRequest, badRequest.StatusCode);
        Assert.Equal(ex.Message, GetProperty(badRequest.Value!, "error"));
    }

    // =====================================================================
    // Upload
    // =====================================================================

    [Fact]
    public async Task Upload_InvokesService_WithDirectoryAndFile()
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

        await controller.Upload("docs", file);

        Assert.Equal("docs", fake.UploadDirPath);
        Assert.Same(file, fake.UploadFile);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public async Task Upload_PassesEmptyString_WhenPathIsNullOrEmpty(string? path)
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

        await controller.Upload(path, file);

        Assert.Equal(string.Empty, fake.UploadDirPath);
    }

    // The happy-path "Upload returns 200 echoing the service value" contract is
    // pinned by the parameterized Upload_ResponsePath_EchoesServiceReturnValue_
    // VerbatimWithoutNormalization test below (it asserts Status200OK + verbatim
    // echo across clean and non-canonical service return values). Per-test
    // variants for empty/null/provided *query* paths add no coverage here because
    // after the refactor the query path no longer influences the response at all —
    // it is forwarded to the service verbatim (pinned by
    // Upload_PassesEmptyString_WhenPathIsNullOrEmpty and
    // Upload_PassesRawPathToService_EvenWhenNonCanonical).

    [Theory]
    [MemberData(nameof(CaughtExceptions))]
    public async Task Upload_WhenServiceThrows_ReturnsBadRequest400_WithErrorMessage(Exception ex)
    {
        var fake = new FakeFileService { UploadException = ex };
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

        var result = await controller.Upload("docs", file);

        var badRequest = Assert.IsType<BadRequestObjectResult>(result);
        Assert.Equal(StatusCodes.Status400BadRequest, badRequest.StatusCode);
        Assert.Equal(ex.Message, GetProperty(badRequest.Value!, "error"));
    }

    // =====================================================================
    // Upload response path sourcing
    //
    // The Upload endpoint's response `path` is the value returned by
    // IFileService.UploadAsync — the service is the single source of truth for
    // the stored file's normalized relative path. The controller must echo
    // that value VERBATIM: it must not re-normalize, strip, backslash-convert,
    // or otherwise mutate the service's return value (the previous
    // controller-side NormalizeRelativePath helper has been removed). These
    // tests pin the echo contract; the normalization itself is now pinned at
    // the service layer in FileServiceTests.
    // =====================================================================

    [Theory]
    [InlineData("docs/report.txt")]
    [InlineData("a/b/c/report.txt")]
    [InlineData("report.txt")]
    [InlineData("docs\\sub\\report.txt")]   // value the OLD controller would have converted to forward slashes
    [InlineData("/docs/report.txt")]        // value the OLD controller would have leading-trimmed
    [InlineData("docs//report.txt")]        // value the OLD controller would have collapsed
    [InlineData("../escape/report.txt")]    // value the OLD controller would have dot-stripped
    [InlineData("")]                        // the service may legitimately return an empty path
    public async Task Upload_ResponsePath_EchoesServiceReturnValue_VerbatimWithoutNormalization(string storedPath)
    {
        // Whatever the service returns must reach the response body unchanged.
        // This proves the controller performs NO path normalization of its own;
        // the service return value is the single source of truth. Had the
        // controller kept a NormalizeRelativePath step, the backslash / leading
        // slash / repeated slash / ".." cases below would be rewritten and this
        // assertion would fail.
        var fake = new FakeFileService { UploadedPath = storedPath };
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("report.txt", "payload");

        var result = await controller.Upload("any/dir", file);

        var ok = Assert.IsType<OkObjectResult>(result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Equal(storedPath, GetProperty(ok.Value!, "path"));
    }

    [Theory]
    [InlineData("docs\\sub")]
    [InlineData("/docs/")]
    [InlineData("./docs")]
    [InlineData("docs/../sub")]
    [InlineData("//docs//sub//")]
    public async Task Upload_PassesRawPathToService_EvenWhenNonCanonical(string path)
    {
        // The service call must NOT be normalized at the controller layer: it
        // still receives the raw query value so its own SafeResolve can sandbox
        // the path. (The response path is sourced from the service's return
        // value, never reconstructed/normalized by the controller.)
        var fake = new FakeFileService();
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("report.txt", "payload");

        await controller.Upload(path, file);

        Assert.Equal(path, fake.UploadDirPath);
    }

    // =====================================================================
    // Download
    // =====================================================================

    [Fact]
    public void Download_ReturnsPhysicalFileResult_WithResolvedPathAndContentType()
    {
        var resolved = Path.Combine(Path.GetTempPath(), "report.txt");
        var fake = new FakeFileService { ResolvedPath = resolved };
        var controller = CreateController(fake);

        var result = controller.Download("report.txt");

        var physical = Assert.IsType<PhysicalFileResult>(result);
        Assert.Equal(resolved, physical.FileName);
        // .txt is mapped to text/plain by the FileExtensionContentTypeProvider.
        Assert.Equal("text/plain", physical.ContentType);
        Assert.Equal("report.txt", physical.FileDownloadName);
    }

    [Fact]
    public void Download_PassesPathToResolveFullPath()
    {
        var fake = new FakeFileService { ResolvedPath = Path.Combine(Path.GetTempPath(), "x") };
        var controller = CreateController(fake);

        controller.Download("some/file.bin");

        Assert.Equal("some/file.bin", fake.ResolvePath);
